class Solution {
    public int smallestRepunitDivByK(int k) {
        int remainder = 0;
        int length = 1;
        while (remainder != 0) {
            remainder = (remainder * 10 + 1) % k;
            length++;
        }
        return remainder == 0 ? length : -1;
    }
}
```
